# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration platform that coordinates users,
projects, tasks, messaging, performance analytics, and reporting.

The implementation is organised as a set of cooperating services that share a
single re-entrant lock and a single global identity counter through a small
``_Context`` object.  Every read accessor returns a deep copy so callers can
never mutate internal state by accident.

Standard library only.
"""

import copy
import csv
import enum
import io
import json
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import Dict, List, Optional, Set


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(enum.Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(enum.Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(enum.Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# Sentinel used to distinguish "argument not provided" from an explicit ``None``.
_UNSET = object()


def _clone(obj):
    """Return a deep copy so internal state cannot be mutated by callers."""
    return copy.deepcopy(obj)


def _clone_all(objs):
    return [copy.deepcopy(o) for o in objs]


# ---------------------------------------------------------------------------
# Shared context: one lock, one id counter, one clock, shared service handles
# ---------------------------------------------------------------------------
class _Context:
    def __init__(self, now):
        self.lock = threading.RLock()
        self.now = now
        self._next_id = 0
        # Service references, wired by the manager after construction.
        self.users = None
        self.projects = None
        self.tasks = None
        self.messages = None
        self.performance = None
        self.reports = None

    def next_id(self):
        with self.lock:
            self._next_id += 1
            return self._next_id


# ---------------------------------------------------------------------------
# User service
# ---------------------------------------------------------------------------
class UserStore:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._users = {}            # type: Dict[int, User]
        self._by_username = {}      # type: Dict[str, int]
        self._by_email = {}         # type: Dict[str, int]

    # -- internal raw access (callers must hold the lock) -------------------
    def require(self, user_id):
        user = self._users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def exists(self, user_id):
        return user_id in self._users

    def all_raw(self):
        return [self._users[k] for k in sorted(self._users)]

    # -- public API ---------------------------------------------------------
    def register(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            uname = (username or "").strip()
            if not uname:
                raise ValidationError("username is required")
            mail = (email or "").strip()
            if not mail or "@" not in mail:
                raise ValidationError("a valid email is required")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if uname in self._by_username:
                raise DuplicateError("username already in use")
            if mail in self._by_email:
                raise DuplicateError("email already in use")
            user = User(
                id=self._ctx.next_id(),
                username=uname,
                email=mail,
                role=role,
                created_at=self._ctx.now(),
            )
            self._users[user.id] = user
            self._by_username[uname] = user.id
            self._by_email[mail] = user.id
            return _clone(user)

    def get(self, user_id):
        with self._lock:
            return _clone(self.require(user_id))

    def list(self):
        with self._lock:
            return _clone_all(self.all_raw())

    def update(self, user_id, username=_UNSET, email=_UNSET, role=_UNSET):
        with self._lock:
            user = self.require(user_id)
            new_username = user.username
            new_email = user.email
            new_role = user.role

            if username is not _UNSET:
                uname = (username or "").strip()
                if not uname:
                    raise ValidationError("username is required")
                owner = self._by_username.get(uname)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already in use")
                new_username = uname

            if email is not _UNSET:
                mail = (email or "").strip()
                if not mail or "@" not in mail:
                    raise ValidationError("a valid email is required")
                owner = self._by_email.get(mail)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already in use")
                new_email = mail

            if role is not _UNSET:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            if new_username != user.username:
                self._by_username.pop(user.username, None)
                self._by_username[new_username] = user_id
                user.username = new_username
            if new_email != user.email:
                self._by_email.pop(user.email, None)
                self._by_email[new_email] = user_id
                user.email = new_email
            user.role = new_role
            return _clone(user)

    def delete(self, user_id):
        with self._lock:
            user = self.require(user_id)
            if self._ctx.projects.owns_any(user_id):
                raise ConflictError("user owns one or more projects")
            if self._ctx.tasks.has_open_tasks(user_id):
                raise ConflictError("user has open task assignments")
            self._users.pop(user_id, None)
            self._by_username.pop(user.username, None)
            self._by_email.pop(user.email, None)
            self._ctx.tasks.detach_assignee(user_id)
            return None


# ---------------------------------------------------------------------------
# Project service
# ---------------------------------------------------------------------------
class ProjectStore:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._projects = {}         # type: Dict[int, Project]

    def require(self, project_id):
        project = self._projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def owns_any(self, user_id):
        return any(p.owner_id == user_id for p in self._projects.values())

    def create(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            self._ctx.users.require(owner_id)
            pname = (name or "").strip()
            if not pname:
                raise ValidationError("project name is required")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            project = Project(
                id=self._ctx.next_id(),
                name=pname,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
            )
            self._projects[project.id] = project
            return _clone(project)

    def get(self, project_id):
        with self._lock:
            return _clone(self.require(project_id))

    def list(self):
        with self._lock:
            return _clone_all(
                [self._projects[k] for k in sorted(self._projects)]
            )

    def update(self, project_id, name=_UNSET, start_date=_UNSET,
               end_date=_UNSET, description=_UNSET):
        with self._lock:
            project = self.require(project_id)
            new_name = project.name
            if name is not _UNSET:
                pname = (name or "").strip()
                if not pname:
                    raise ValidationError("project name is required")
                new_name = pname

            new_start = project.start_date if start_date is _UNSET else start_date
            new_end = project.end_date if end_date is _UNSET else end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            new_desc = (
                project.description if description is _UNSET
                else (description or "")
            )

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            project.description = new_desc
            return _clone(project)

    def delete(self, project_id):
        with self._lock:
            self.require(project_id)
            removed_task_ids = self._ctx.tasks.remove_project(project_id)
            self._ctx.messages.purge_project(project_id, removed_task_ids)
            self._projects.pop(project_id, None)
            return None


# ---------------------------------------------------------------------------
# Task service
# ---------------------------------------------------------------------------
class TaskStore:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._tasks = {}            # type: Dict[int, Task]
        self._by_project = {}       # type: Dict[int, List[int]]
        self._by_assignee = {}      # type: Dict[int, Set[int]]

    # -- internal raw access (callers must hold the lock) -------------------
    def require(self, task_id):
        task = self._tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def iter_project(self, project_id):
        return [self._tasks[t] for t in self._by_project.get(project_id, [])]

    def iter_assignee(self, user_id):
        return [
            self._tasks[t]
            for t in sorted(self._by_assignee.get(user_id, set()))
        ]

    def has_open_tasks(self, user_id):
        for tid in self._by_assignee.get(user_id, set()):
            if self._tasks[tid].status != TaskStatus.COMPLETED:
                return True
        return False

    def detach_assignee(self, user_id):
        self._by_assignee.pop(user_id, None)

    def remove_project(self, project_id):
        removed = list(self._by_project.pop(project_id, []))
        for tid in removed:
            task = self._tasks.pop(tid, None)
            if task is not None and task.assignee_id is not None:
                bucket = self._by_assignee.get(task.assignee_id)
                if bucket is not None:
                    bucket.discard(tid)
                    if not bucket:
                        del self._by_assignee[task.assignee_id]
        return removed

    def _set_assignee(self, task, user_id):
        old = task.assignee_id
        if old is not None:
            bucket = self._by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    del self._by_assignee[old]
        task.assignee_id = user_id
        if user_id is not None:
            self._by_assignee.setdefault(user_id, set()).add(task.id)

    # -- public API ---------------------------------------------------------
    def create(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._ctx.projects.require(project_id)
            ttitle = (title or "").strip()
            if not ttitle:
                raise ValidationError("task title is required")
            if assignee_id is not None:
                self._ctx.users.require(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")
            task = Task(
                id=self._ctx.next_id(),
                project_id=project_id,
                title=ttitle,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._ctx.now(),
            )
            self._tasks[task.id] = task
            self._by_project.setdefault(project_id, []).append(task.id)
            if assignee_id is not None:
                self._by_assignee.setdefault(assignee_id, set()).add(task.id)
            return _clone(task)

    def get(self, task_id):
        with self._lock:
            return _clone(self.require(task_id))

    def list_by_project(self, project_id):
        with self._lock:
            self._ctx.projects.require(project_id)
            tids = sorted(self._by_project.get(project_id, []))
            return [_clone(self._tasks[t]) for t in tids]

    def list_by_assignee(self, user_id):
        with self._lock:
            self._ctx.users.require(user_id)
            tids = sorted(self._by_assignee.get(user_id, set()))
            return [_clone(self._tasks[t]) for t in tids]

    def assign(self, task_id, assignee_id):
        with self._lock:
            task = self.require(task_id)
            self._ctx.users.require(assignee_id)
            self._set_assignee(task, assignee_id)
            return _clone(task)

    def reassign(self, task_id, assignee_id):
        return self.assign(task_id, assignee_id)

    def unassign(self, task_id):
        with self._lock:
            task = self.require(task_id)
            self._set_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self.require(task_id)
            if deadline is not None:
                project = self._ctx.projects.require(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError(
                        "deadline cannot precede project start"
                    )
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self.require(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._ctx.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _clone(task)


# ---------------------------------------------------------------------------
# Messaging service
# ---------------------------------------------------------------------------
class MessageStore:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._messages = {}         # type: Dict[int, Message]
        self._by_project = {}       # type: Dict[int, List[int]]
        self._by_task = {}          # type: Dict[int, List[int]]

    def require(self, message_id):
        message = self._messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    def _build_attachments(self, items, uploader_id, when):
        attachments = []
        for filename, data in items:
            fname = (filename or "").strip()
            if not fname:
                raise ValidationError("attachment filename is required")
            attachments.append(
                Attachment(
                    filename=fname,
                    size=len(data) if data is not None else 0,
                    uploaded_by=uploader_id,
                    uploaded_at=when,
                )
            )
        return attachments

    def post(self, author_id, body, project_id=None, task_id=None,
             parent_id=None, attachments=None):
        with self._lock:
            self._ctx.users.require(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._ctx.projects.require(project_id)
            if task_id is not None:
                self._ctx.tasks.require(task_id)
            if parent_id is not None:
                self.require(parent_id)

            now = self._ctx.now()
            built = self._build_attachments(
                attachments or [], author_id, now
            )
            text = body if body is not None else ""
            if not text.strip() and not built:
                raise ValidationError(
                    "message body or an attachment is required"
                )

            message = Message(
                id=self._ctx.next_id(),
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=now,
                edited_at=None,
            )
            self._messages[message.id] = message
            if project_id is not None:
                self._by_project.setdefault(project_id, []).append(message.id)
            if task_id is not None:
                self._by_task.setdefault(task_id, []).append(message.id)
            return _clone(message)

    def edit(self, message_id, editor_id, new_body):
        with self._lock:
            message = self.require(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            text = new_body if new_body is not None else ""
            if not text.strip() and not message.attachments:
                raise ValidationError("message body cannot be empty")
            message.body = text
            message.edited_at = self._ctx.now()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self.require(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may add attachments"
                )
            built = self._build_attachments(
                [(filename, data)], uploader_id, self._ctx.now()
            )
            message.attachments.extend(built)
            return _clone(message)

    def list_by_project(self, project_id):
        with self._lock:
            self._ctx.projects.require(project_id)
            mids = sorted(self._by_project.get(project_id, []))
            return [_clone(self._messages[m]) for m in mids]

    def list_by_task(self, task_id):
        with self._lock:
            self._ctx.tasks.require(task_id)
            mids = sorted(self._by_task.get(task_id, []))
            return [_clone(self._messages[m]) for m in mids]

    def delete(self, message_id, requester_id):
        with self._lock:
            message = self.require(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            self._remove(message)
            return None

    def _remove(self, message):
        self._messages.pop(message.id, None)
        if message.project_id is not None:
            bucket = self._by_project.get(message.project_id)
            if bucket is not None and message.id in bucket:
                bucket.remove(message.id)
                if not bucket:
                    del self._by_project[message.project_id]
        if message.task_id is not None:
            bucket = self._by_task.get(message.task_id)
            if bucket is not None and message.id in bucket:
                bucket.remove(message.id)
                if not bucket:
                    del self._by_task[message.task_id]

    def purge_project(self, project_id, task_ids):
        """Remove messages tied to a deleted project or its tasks."""
        task_id_set = set(task_ids)
        doomed = [
            m for m in self._messages.values()
            if m.project_id == project_id or m.task_id in task_id_set
        ]
        for message in doomed:
            self._remove(message)


# ---------------------------------------------------------------------------
# Performance / analytics service
# ---------------------------------------------------------------------------
class PerformanceService:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock
        self._ratings = {}              # type: Dict[int, Rating]
        self._by_ratee = {}             # type: Dict[int, List[int]]

    # -- internal computation helpers (callers hold the lock) --------------
    def _completion_rate(self, tasks):
        if not tasks:
            return 0.0
        completed = sum(
            1 for t in tasks if t.status == TaskStatus.COMPLETED
        )
        return completed / float(len(tasks))

    def _average_completion_time(self, tasks):
        durations = []
        for task in tasks:
            if (task.status == TaskStatus.COMPLETED
                    and task.started_at is not None
                    and task.completed_at is not None):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        if not durations:
            return None
        return sum(durations) / float(len(durations))

    def _rating_stats(self, user_id):
        rating_ids = self._by_ratee.get(user_id, [])
        ratings = [self._ratings[r] for r in rating_ids]
        count = len(ratings)
        average = (
            sum(r.score for r in ratings) / float(count) if count else 0.0
        )
        return count, average, ratings

    # -- public API ---------------------------------------------------------
    def completion_rate(self, user_id):
        with self._lock:
            self._ctx.users.require(user_id)
            return self._completion_rate(self._ctx.tasks.iter_assignee(user_id))

    def average_completion_time(self, user_id):
        with self._lock:
            self._ctx.users.require(user_id)
            return self._average_completion_time(
                self._ctx.tasks.iter_assignee(user_id)
            )

    def submit_rating(self, rater_id, ratee_id, score, feedback="",
                      task_id=None):
        with self._lock:
            self._ctx.users.require(rater_id)
            self._ctx.users.require(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._ctx.tasks.require(task_id)
            rating = Rating(
                id=self._ctx.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._ctx.now(),
            )
            self._ratings[rating.id] = rating
            self._by_ratee.setdefault(ratee_id, []).append(rating.id)
            return _clone(rating)

    def ratings_summary(self, user_id):
        with self._lock:
            self._ctx.users.require(user_id)
            count, average, ratings = self._rating_stats(user_id)
            return {
                "count": count,
                "average": average,
                "ratings": _clone_all(ratings),
            }

    def user_dashboard(self, user_id):
        with self._lock:
            self._ctx.users.require(user_id)
            tasks = self._ctx.tasks.iter_assignee(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            count, average, _ = self._rating_stats(user_id)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": count,
                "rating_average": average,
            }


# ---------------------------------------------------------------------------
# Reporting service
# ---------------------------------------------------------------------------
class ReportService:
    def __init__(self, ctx):
        self._ctx = ctx
        self._lock = ctx.lock

    def _user_row(self, user_id, tasks):
        perf = self._ctx.performance
        count, average, _ = perf._rating_stats(user_id)
        completed = sum(
            1 for t in tasks if t.status == TaskStatus.COMPLETED
        )
        return {
            "user_id": user_id,
            "total_tasks": len(tasks),
            "completed_tasks": completed,
            "completion_rate": perf._completion_rate(tasks),
            "average_completion_time": perf._average_completion_time(tasks),
            "rating_count": count,
            "rating_average": average,
        }

    def project_progress(self, project_id):
        with self._lock:
            self._ctx.projects.require(project_id)
            tasks = self._ctx.tasks.iter_project(project_id)
            now = self._ctx.now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (task.deadline is not None
                        and task.deadline < now
                        and task.status != TaskStatus.COMPLETED):
                    overdue += 1
                if task.assignee_id is not None:
                    per_assignee.setdefault(task.assignee_id, []).append(task)

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            per_assignee_stats = {}
            for uid, assigned in per_assignee.items():
                done = sum(
                    1 for t in assigned if t.status == TaskStatus.COMPLETED
                )
                per_assignee_stats[uid] = {
                    "total_tasks": len(assigned),
                    "completed_tasks": done,
                    "completion_rate": (
                        done / float(len(assigned)) if assigned else 0.0
                    ),
                }

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (
                    completed / float(total) if total else 0.0
                ),
                "overdue_tasks": overdue,
                "per_assignee": per_assignee_stats,
            }

    def team_performance(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._ctx.projects.require(project_id)
                scoped_tasks = self._ctx.tasks.iter_project(project_id)
            else:
                scoped_tasks = None  # global -> use each user's full set

            if scoped_tasks is None:
                # Global: every user that has at least one assigned task.
                assignee_ids = set()
                for user in self._ctx.users.all_raw():
                    if self._ctx.tasks.iter_assignee(user.id):
                        assignee_ids.add(user.id)
                rows = [
                    self._user_row(uid, self._ctx.tasks.iter_assignee(uid))
                    for uid in sorted(assignee_ids)
                ]
            else:
                grouped = {}
                for task in scoped_tasks:
                    if task.assignee_id is not None:
                        grouped.setdefault(task.assignee_id, []).append(task)
                rows = [
                    self._user_row(uid, grouped[uid])
                    for uid in sorted(grouped)
                ]

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance(self, user_id):
        with self._lock:
            self._ctx.users.require(user_id)
            tasks = self._ctx.tasks.iter_assignee(user_id)
            row = self._user_row(user_id, tasks)
            count, average, ratings = self._ctx.performance._rating_stats(
                user_id
            )
            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": row["total_tasks"],
                "completed_tasks": row["completed_tasks"],
                "completion_rate": row["completion_rate"],
                "average_completion_time": row["average_completion_time"],
                "rating_count": count,
                "rating_average": average,
                "tasks": _clone_all(tasks),
            }
            return report

    # -- export -------------------------------------------------------------
    def export(self, report, fmt):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a mapping")
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat")
            if fmt == ReportFormat.CSV:
                return _report_to_csv(report)
            return _report_to_pdf(report)


