# Export helpers
# ---------------------------------------------------------------------------
def _csv_cell(value):
    if value is None:
        return ""
    if isinstance(value, bool):
        return str(value)
    if isinstance(value, (str, int, float)):
        return value
    if isinstance(value, enum.Enum):
        return value.value
    try:
        return json.dumps(value, default=str, sort_keys=True)
    except (TypeError, ValueError):
        return str(value)


def _report_to_csv(report):
    output = io.StringIO()
    writer = csv.writer(output)
    rows = report.get("rows")
    if isinstance(rows, list):
        columns = []
        for row in rows:
            if isinstance(row, dict):
                for key in row:
                    if key not in columns:
                        columns.append(key)
        if not columns:
            columns = [
                "user_id", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_count", "rating_average",
            ]
        writer.writerow(columns)
        for row in rows:
            if isinstance(row, dict):
                writer.writerow([_csv_cell(row.get(c)) for c in columns])
    else:
        writer.writerow(["field", "value"])
        for key, value in report.items():
            writer.writerow([key, _csv_cell(value)])
    return output.getvalue()


def _pdf_escape(text):
    return (
        text.replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
    )


def _report_lines(report):
    lines = ["Report: {0}".format(report.get("report_type", "report"))]
    for key, value in report.items():
        if key == "report_type":
            continue
        lines.append("{0}: {1}".format(key, _csv_cell(value)))
    return lines


def _report_to_pdf(report):
    text_lines = _report_lines(report)

    parts = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
    first = True
    for line in text_lines:
        safe = _pdf_escape(str(line))
        if first:
            parts.append("({0}) Tj".format(safe))
            first = False
        else:
            parts.append("T*")
            parts.append("({0}) Tj".format(safe))
    parts.append("ET")
    content = "\n".join(parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
        b"<< /Length " + str(len(content)).encode("ascii") + b" >>\n"
        b"stream\n" + content + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets = []
    for index, obj in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += str(index).encode("ascii") + b" 0 obj\n" + obj + b"\nendobj\n"

    xref_pos = len(pdf)
    size = len(objects) + 1
    pdf += b"xref\n"
    pdf += b"0 " + str(size).encode("ascii") + b"\n"
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += ("%010d 00000 n \n" % offset).encode("ascii")
    pdf += b"trailer\n<< /Size " + str(size).encode("ascii")
    pdf += b" /Root 1 0 R >>\n"
    pdf += b"startxref\n" + str(xref_pos).encode("ascii") + b"\n%%EOF\n"
    return bytes(pdf)


